INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Pratiques managériales avec IA', 'Formation sur l’utilisation de l’intelligence artificielle pour améliorer les pratiques managériales et la performance des équipes.', 2, 250000.00, 'entreprise', '2026-12-15', 30, '2026-01-14 12:38:42', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre l’impact de l’IA sur le management\n• Utiliser des outils IA pour optimiser la prise de décision\n• Développer des stratégies managériales basées sur les données\n• Améliorer la communication et la motivation des équipes\n• Renforcer l’efficacité et l’innovation dans la gestion\n\n--- OBJECTIFS DÉTAILLÉS ---\nInitier les managers aux pratiques managériales assistées par IA, leur apprendre à utiliser des outils intelligents pour optimiser la prise de décision, améliorer la performance et renforcer la cohésion des équipes.\n\n--- PRÉREQUIS ---\nExpérience préalable en management ou gestion d’équipe souhaitée.\n\n--- CONTENU ---\nModule 1 : Introduction à l’IA et au management\nModule 2 : Outils IA pour la prise de décision\nModule 3 : Stratégies managériales basées sur les données\nModule 4 : Communication et motivation assistées par IA\nModule 5 : Gestion des performances et innovation\nModule 6 : Atelier pratique – Mise en œuvre d’un plan managérial avec IA\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nManagers, responsables RH, chefs de projet et dirigeants souhaitant intégrer l’IA dans leurs pratiques managériales.\n\n--- MÉTHODES ---\nPrésentations interactives, démonstrations, ateliers pratiques, études de cas et simulations.\n\n--- SUPPORTS ---\nOutils IA de management, logiciels de suivi de performance, supports PDF, slides et tutoriels pratiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
